<script setup lang="ts">
import { computed, ref } from 'vue'
import QRCode from 'qrcode'
import { CheckCircle2, Copy, EyeOff, Fingerprint, KeyRound, LockKeyhole, ServerCog, ShieldCheck } from 'lucide-vue-next'
import Button from '@/components/ui/Button.vue'
import StatusBadge from '@/components/ui/StatusBadge.vue'
import { confirmTOTP,enrollTOTP } from '@/lib/api'
import { useAuthStore } from '@/stores/auth'
const auth=useAuthStore();const secret=ref('');const qr=ref('');const code=ref('');const error=ref('');const enabled=ref(auth.user?.totp_enabled??false);const copied=ref(false);const enrolling=computed(()=>!!secret.value&&!enabled.value)
const start=async()=>{error.value='';try{const data=await enrollTOTP();secret.value=data.secret;qr.value=await QRCode.toDataURL(data.otpauth_uri,{width:220,margin:1,color:{dark:'#07110d',light:'#f8fafc'}})}catch(e:any){error.value=e?.response?.data?.error?.message||'Não foi possível iniciar o TOTP.'}}
const confirm=async()=>{error.value='';try{await confirmTOTP(code.value);enabled.value=true;secret.value='';qr.value='';await auth.initialize()}catch{error.value='Código inválido. Verifique o relógio do dispositivo.'}}
const copy=async()=>{await navigator.clipboard.writeText(secret.value);copied.value=true;window.setTimeout(()=>copied.value=false,1800)}
</script>
<template><div class="mx-auto max-w-6xl space-y-5"><header><div class="flex items-center gap-2 font-mono text-[10px] uppercase tracking-widest text-signal"><ShieldCheck class="h-3.5 w-3.5"/>Segurança e configuração</div><h1 class="mt-3 text-3xl font-semibold tracking-tight">Central de configurações</h1><p class="mt-2 text-sm text-muted">Identidade, postura de segredos e políticas operacionais do plano de controle.</p></header><section class="grid gap-5 lg:grid-cols-[1.4fr_.8fr]"><article class="rounded-xl border border-line bg-panel/65"><header class="flex items-start gap-4 border-b border-line p-5"><div class="grid h-10 w-10 place-items-center rounded-xl border border-signal/20 bg-signal/[.07]"><Fingerprint class="h-5 w-5 text-signal"/></div><div class="flex-1"><div class="flex flex-wrap items-center gap-3"><h2 class="text-sm font-medium">Senha descartável baseada em tempo</h2><StatusBadge :status="enabled?'healthy':'warning'" :label="enabled?'habilitado':'obrigatório'"/></div><p class="mt-1 text-xs leading-5 text-muted">RFC 6238 · SHA-1 · 30 segundos · segredo AES-256-GCM em repouso</p></div></header><div class="p-5"><div v-if="enabled" class="flex items-center gap-3 rounded-xl border border-signal/15 bg-signal/[.04] p-4"><CheckCircle2 class="h-5 w-5 text-signal"/><div><p class="text-sm text-slate-200">Segundo fator ativo</p><p class="mt-1 text-xs text-muted">Ações críticas remotas e cloud exigem um código válido.</p></div></div><div v-else-if="!enrolling"><p class="max-w-xl text-sm leading-6 text-muted">Use Aegis, 1Password, Bitwarden ou outro autenticador compatível. O segredo aparece apenas durante este fluxo.</p><Button class="mt-5" @click="start"><KeyRound class="h-4 w-4"/>Configurar autenticador</Button></div><div v-else class="grid gap-6 md:grid-cols-[220px_1fr]"><img :src="qr" alt="QR code para configurar TOTP" class="h-[220px] w-[220px] rounded-xl bg-white p-2"/><div><p class="text-sm font-medium">Escaneie e confirme</p><p class="mt-2 text-xs leading-5 text-muted">Se não puder escanear, copie a chave manualmente:</p><button class="mt-3 flex w-full cursor-pointer items-center gap-2 rounded-lg border border-line bg-slate-950/60 p-3 text-left font-mono text-xs text-slate-300 hover:border-slate-600" @click="copy"><span class="min-w-0 flex-1 break-all">{{secret}}</span><Copy class="h-4 w-4 shrink-0 text-muted"/></button><p v-if="copied" class="mt-2 text-[10px] text-signal">Copiado para a área de transferência.</p><form class="mt-4 flex gap-2" @submit.prevent="confirm"><input v-model="code" required inputmode="numeric" pattern="[0-9]{6}" maxlength="6" class="field mt-0 font-mono tracking-[.35em]" placeholder="000000"/><Button type="submit">Confirmar</Button></form></div></div><p v-if="error" class="mt-4 rounded-lg border border-danger/20 bg-danger/5 p-3 text-xs text-danger">{{error}}</p></div></article><aside class="space-y-4"><article class="rounded-xl border border-line bg-panel/65 p-5"><div class="flex items-center gap-3"><LockKeyhole class="h-4 w-4 text-signal"/><h2 class="text-sm font-medium">Postura da sessão</h2></div><dl class="mt-4 space-y-3 text-xs"><div class="flex justify-between gap-3"><dt class="text-muted">Identidade</dt><dd class="text-right text-slate-300">{{auth.user?.email}}</dd></div><div class="flex justify-between"><dt class="text-muted">Papéis</dt><dd class="font-mono text-slate-300">{{auth.user?.roles.join(', ')||'nenhum'}}</dd></div><div class="flex justify-between"><dt class="text-muted">CSRF</dt><dd class="text-signal">Token rotativo</dd></div><div class="flex justify-between"><dt class="text-muted">Cookie</dt><dd class="text-signal">HttpOnly · Strict</dd></div></dl></article><article class="rounded-xl border border-warning/15 bg-warning/[.035] p-5"><div class="flex items-center gap-3"><EyeOff class="h-4 w-4 text-warning"/><h2 class="text-sm font-medium">Política de segredos</h2></div><p class="mt-3 text-xs leading-5 text-muted">Valores sensíveis não são recuperáveis pela UI. A interface mostra apenas estado, origem e última rotação. Alterações devem ocorrer pelo mecanismo seguro do ambiente.</p><RouterLink to="/integrations" class="mt-4 inline-flex text-xs text-warning hover:text-amber-300">Abrir integrações →</RouterLink></article></aside></section><section class="grid gap-4 md:grid-cols-3"><article v-for="policy in [{title:'Autoproteção',detail:'Alvo local protegido contra ações destrutivas',icon:ShieldCheck,status:'Aplicada'},{title:'Integridade da auditoria',detail:'Eventos encadeados por hash e request ID',icon:LockKeyhole,status:'Habilitada'},{title:'Configuração de execução',detail:'Configuração sensível fora do repositório',icon:ServerCog,status:'Externa'}]" :key="policy.title" class="rounded-xl border border-line bg-panel/50 p-5"><component :is="policy.icon" class="h-5 w-5 text-pulse"/><div class="mt-4 flex items-center justify-between gap-2"><h2 class="text-sm font-medium">{{policy.title}}</h2><StatusBadge status="healthy" :label="policy.status"/></div><p class="mt-2 text-xs leading-5 text-muted">{{policy.detail}}</p></article></section></div></template>
